import{_ as t,o,c as r,ag as a}from"./chunks/framework.YaIgwL5o.js";const g=JSON.parse('{"title":"Presenting & Export","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/presenting.md","filePath":"tutorials/presenting.md"}'),n={name:"tutorials/presenting.md"};function i(s,e,l,d,h,p){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="presenting-export" tabindex="-1">Presenting &amp; Export <a class="header-anchor" href="#presenting-export" aria-label="Permalink to &quot;Presenting &amp; Export&quot;">​</a></h1><h2 id="present-mode" tabindex="-1">Present mode <a class="header-anchor" href="#present-mode" aria-label="Permalink to &quot;Present mode&quot;">​</a></h2><p>Click the <strong>Present</strong> button (play icon) in the top-right toolbar to open the full presentation in a new window.</p><h3 id="controls-in-present-mode" tabindex="-1">Controls in present mode <a class="header-anchor" href="#controls-in-present-mode" aria-label="Permalink to &quot;Controls in present mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>Right</code> / <code>Space</code></td><td>Next slide</td></tr><tr><td><code>Left</code></td><td>Previous slide</td></tr><tr><td><code>S</code></td><td>Open speaker notes</td></tr><tr><td><code>F</code></td><td>Toggle fullscreen</td></tr><tr><td><code>Escape</code></td><td>Exit fullscreen or close overlay</td></tr><tr><td><code>O</code></td><td>Overview / slide grid</td></tr></tbody></table><h2 id="preview-a-single-slide" tabindex="-1">Preview a single slide <a class="header-anchor" href="#preview-a-single-slide" aria-label="Permalink to &quot;Preview a single slide&quot;">​</a></h2><p>To test a single slide without presenting the entire deck:</p><ol><li>Click the <strong>Preview Slide N</strong> button at the top of the right panel.</li><li>The current slide opens in a new window, fully rendered in present mode.</li></ol><p>This is useful for testing HTML embeds, animations, and interactive features without navigating through the full deck.</p><h2 id="speaker-notes" tabindex="-1">Speaker notes <a class="header-anchor" href="#speaker-notes" aria-label="Permalink to &quot;Speaker notes&quot;">​</a></h2><ol><li>In the editor, click the <strong>Notes</strong> area at the bottom of the properties panel.</li><li>Type your speaker notes for the current slide.</li><li>In present mode, press <code>S</code> to open the speaker view with notes, timer, and next-slide preview.</li></ol><h2 id="themes" tabindex="-1">Themes <a class="header-anchor" href="#themes" aria-label="Permalink to &quot;Themes&quot;">​</a></h2><p>Change the visual theme in the toolbar under <strong>Theme</strong>:</p><ul><li>Black, White, League, Beige, Sky, Night, Serif, Simple, Solarized, Moon, Dracula</li></ul><p>Themes affect the background color, text color, and heading styles. Element-level formatting takes precedence over theme defaults.</p><h2 id="footer-page-numbers" tabindex="-1">Footer &amp; page numbers <a class="header-anchor" href="#footer-page-numbers" aria-label="Permalink to &quot;Footer &amp; page numbers&quot;">​</a></h2><ol><li>Open footer settings in the toolbar.</li><li>Configure: <ul><li><strong>Section labels</strong> — show active section in a progress bar</li><li><strong>Page numbers</strong> — <code>n/total</code> or just <code>n</code></li><li><strong>Clock / Timer</strong> — 12h clock, 24h clock, count-up or count-down timer</li></ul></li></ol><h2 id="export-options" tabindex="-1">Export options <a class="header-anchor" href="#export-options" aria-label="Permalink to &quot;Export options&quot;">​</a></h2><h3 id="html" tabindex="-1">HTML <a class="header-anchor" href="#html" aria-label="Permalink to &quot;HTML&quot;">​</a></h3><p>Click <strong>Export</strong> &gt; <strong>Download HTML</strong> to get a self-contained HTML file. All fonts, scripts, and images (if from URLs) are loaded via CDN. The file can be opened in any browser without a server.</p><h3 id="single-slide-html" tabindex="-1">Single slide HTML <a class="header-anchor" href="#single-slide-html" aria-label="Permalink to &quot;Single slide HTML&quot;">​</a></h3><p>Click <strong>Export</strong> &gt; <strong>Export Slide HTML</strong> to download just the current slide.</p><h3 id="pdf" tabindex="-1">PDF <a class="header-anchor" href="#pdf" aria-label="Permalink to &quot;PDF&quot;">​</a></h3><p>Click <strong>Export</strong> &gt; <strong>Export PDF</strong> to generate a print-ready PDF with one page per slide. Fragment states are expanded into separate pages.</p><h3 id="powerpoint" tabindex="-1">PowerPoint <a class="header-anchor" href="#powerpoint" aria-label="Permalink to &quot;PowerPoint&quot;">​</a></h3><p>Click <strong>Export</strong> &gt; <strong>Export PPTX</strong> to generate a PowerPoint file. Text, shapes, and images are converted to native PowerPoint objects.</p><h2 id="sharing" tabindex="-1">Sharing <a class="header-anchor" href="#sharing" aria-label="Permalink to &quot;Sharing&quot;">​</a></h2><ol><li>Click the <strong>Share</strong> button in the toolbar.</li><li>Toggle sharing on. A shareable URL is generated.</li><li>Anyone with the link can view the presentation in present mode (read-only).</li><li>Toggle sharing off to revoke access.</li></ol><h3 id="example-exported-slide" tabindex="-1">Example: exported slide <a class="header-anchor" href="#example-exported-slide" aria-label="Permalink to &quot;Example: exported slide&quot;">​</a></h3><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/slide-export.html" style="width:100%;height:220px;border:none;"></iframe></div>',30)])])}const u=t(n,[["render",i]]);export{g as __pageData,u as default};
